                    break
            if found is None or found in kept:
                break
            kept.insert(0, found)
        return kept

    def _build_summary(self, messages: list[dict]) -> dict:
        """统计摘要 fallback"""
        user_msgs = sum(1 for m in messages if m.get("role") == "user")
        assistant_msgs = sum(1 for m in messages if m.get("role") == "assistant")
