"""记忆召回机制"""

from .store import MemoryStore


class MemoryRecall:
    """记忆召回 - 根据上下文检索相关记忆"""

    def __init__(self, store: MemoryStore):
        self.store = store

    def recall(self, context: str, max_results: int = 5) -> list[dict]:
        """根据上下文召回相关记忆"""
        # 简单实现：基于关键词搜索
        results = self.store.search(context)
        return results[:max_results]

    def recall_by_tag(self, tag: str) -> list[dict]:
        """按标签召回记忆"""
        keys = self.store.list_keys(tag=tag)
        memories = []
        for key in keys:
            memory = self.store.load(key)
            if memory:
                memories.append(memory)
        return memories

    def get_relevant_context(self, query: str) -> str:
        """获取相关上下文文本"""
        memories = self.recall(query)
        if not memories:
            return ""

        context_parts = []
        for m in memories:
            context_parts.append(f"[{m['key']}]: {m['value']}")

        return "\n".join(context_parts)

"""记忆存储引擎"""

import json
from pathlib import Path
from typing import Optional
from datetime import datetime


class MemoryStore:
    """持久化记忆存储"""

    def __init__(self, base_path: str = None):
        self.base_path = Path(base_path or "~/.merco/memory").expanduser()
        self.base_path.mkdir(parents=True, exist_ok=True)

    def save(self, key: str, value: dict, tags: list = None):
        """保存记忆"""
        entry = {
            "key": key,
            "value": value,
            "tags": tags or [],
            "created_at": datetime.now().isoformat(),
        }

        file_path = self.base_path / f"{key}.json"
        with open(file_path, "w") as f:
            json.dump(entry, f, indent=2)

    def load(self, key: str) -> Optional[dict]:
        """加载记忆"""
        file_path = self.base_path / f"{key}.json"
        if not file_path.exists():
            return None

        with open(file_path) as f:
            return json.load(f)

    def delete(self, key: str):
        """删除记忆"""
        file_path = self.base_path / f"{key}.json"
        if file_path.exists():
            file_path.unlink()

    def list_keys(self, tag: str = None) -> list[str]:
        """列出所有记忆键"""
        keys = []
