    # ── 私有方法 ─────────────────────────────────────────────────

    def _build_params(
        self, messages: list[dict], tools: list[dict] | None,
        tool_choice: str | dict[str, Any], stream: bool = False,
    ) -> dict:
        """构造 API 请求参数"""
        params = {
            "model": self.model,
            "messages": _clean_surrogates(messages),
            "temperature": self.temperature,
            "max_tokens": self.max_tokens,
        }
        if stream:
            params["stream"] = True
        if tools:
            params["tools"] = tools
            params["tool_choice"] = tool_choice
        return params

    async def _request(self, params: dict):
        """发送请求（含 cooldown），不重试。错误原样上抛交 Agent RecoveryPipeline。"""
        logger.debug("→ API 请求: model=%s messages=%d tools=%d",
                     self.model, len(params.get("messages", [])),
                     len(params.get("tools", [])))

        if self.cooldown > 0:
            elapsed = time.monotonic() - self._last_request_time
            if elapsed < self.cooldown:
                wait = self.cooldown - elapsed
                logger.debug("⏳ 冷却 %.1fs（距上次请求 %.1fs）", wait, elapsed)
                await asyncio.sleep(wait)

        response = await self.client.chat.completions.create(**params)
        self._last_request_time = time.monotonic()
        return response

    @staticmethod
    def _parse_response(response) -> dict:
        """解析完整响应"""
        choice = response.choices[0]
        message = choice.message

        result = {
            "role": message.role,
            "content": message.content or "",
            "reasoning": _extract_reasoning(message),
            "finish_reason": choice.finish_reason,
            "usage": {
                "prompt_tokens": response.usage.prompt_tokens if response.usage else 0,
                "completion_tokens": response.usage.completion_tokens if response.usage else 0,
                "total_tokens": response.usage.total_tokens if response.usage else 0,
            },
        }

        if message.tool_calls:
            result["tool_calls"] = [

"content": message.content or "",
            "reasoning": _extract_reasoning(message),
            "finish_reason": choice.finish_reason,
            "usage": {
                "prompt_tokens": response.usage.prompt_tokens if response.usage else 0,
                "completion_tokens": response.usage.completion_tokens if response.usage else 0,
                "total_tokens": response.usage.total_tokens if response.usage else 0,
            },
        }

        if message.tool_calls:
            result["tool_calls"] = [
                {
                    "id": tc.id,
                    "name": tc.function.name,
                    "arguments": json.loads(tc.function.arguments),
                }
                for tc in message.tool_calls
            ]

        return result

    @staticmethod
    def _parse_chunk(chunk) -> Optional[dict]:
        """解析流式块"""
        choice = chunk.choices[0] if chunk.choices else None
        if not choice:
            return None

        delta = choice.delta
        result = {}
        if delta.content:
            result["content"] = delta.content
        reasoning = _extract_reasoning(delta)
        if reasoning:
            result["reasoning"] = reasoning
        if delta.tool_calls:
            result["tool_calls"] = [
                {
                    "index": tc.index,
                    "id": tc.id,
                    "name": tc.function.name,
                    "arguments": tc.function.arguments,
                }
                for tc in delta.tool_calls
            ]

        if choice.finish_reason:
            result["finish_reason"] = choice.finish_reason
        if hasattr(chunk, "usage") and chunk.usage:
            result["usage"] = {
                "prompt_tokens": chunk.usage.prompt_tokens,
                "completion_tokens": chunk.usage.completion_tokens,
                "total_tokens": chunk.usage.total_tokens,
            }
        return result if result else None

